create table dirkspzm32.aps_plan_op_a (
    sid                            varchar2(2 char) default '01' not null enable,
    firma_nr                       number(2, 0) default 1 not null enable,
    aps_plan_status                varchar2(3 char) not null enable,
    aps_plan_auftrag_nr            number(*, 0) not null enable,
    aps_plan_ag                    number(*, 0) not null enable,
    aps_plan_ag_upos               number(*, 0) not null enable,
    activity_id                    number(*, 0) not null enable,
    alternative_id                 varchar2(50 char) not null enable,
    ag_text1                       varchar2(255 char),
    ag_text2                       varchar2(255 char),
    ag_text3                       varchar2(255 char),
    ag_bez1                        varchar2(255 char),
    ag_bez2                        varchar2(255 char),
    activity_type                  number(*, 0),
    date_end                       date,
    date_start                     date,
    date_start_fix                 date default '01.01.1900',
    duration_fix                   number(*, 0) default - 1,
    earliest_start_date            date,
    info_date_earliest_end_initial date,
    info_date_earliest_end_mat     date,
    info_date_earliest_end_sched   date,
    info_date_earliest_start_init  date,
    info_date_earliest_start_mat   date,
    info_date_earliest_start_sched date,
    info_date_end_initial          date,
    info_date_latest_end_initial   date,
    info_date_latest_end_mat       date,
    info_date_latest_end_sched     date,
    info_date_latest_start_initial date,
    info_date_latest_start_mat     date,
    info_date_latest_start_sched   date,
    info_date_start_initial        date,
    info_debug                     varchar2(4000 char),
    info_duration                  number(*, 6),
    info_note                      varchar2(4000 char),
    info_setup                     varchar2(4000 char),
    info_time_buffer_initial       number(*, 6),
    info_time_buffer_latest_end    number(*, 6),
    info_time_buffer_material      number(*, 6),
    info_time_buffer_scheduling    number(*, 6),
    info_value_workcenter          number(*, 6),
    info_value_worker              number(*, 6),
    info_worker_utilization        number(*, 6),
    job_parallel_id                varchar2(50 char),
    job_sequential_id              varchar2(50 char),
    last_confirmation_date         varchar2(19 char),
    operation_type                 number(*, 0) default 1,
    priority_value                 number(*, 0) default - 1,
    soll_menge                     number(*, 3),
    scheduling_level               number(*, 0) default 4,
    status                         number(*, 0) default 1,
    erstell_datum                  date default sysdate not null enable,
    bearb_datum                    date
);

alter table dirkspzm32.aps_plan_op_a
    add constraint pk_aps_plan_op_a
        primary key ( aps_plan_status,
                      aps_plan_auftrag_nr,
                      aps_plan_ag,
                      aps_plan_ag_upos,
                      activity_id,
                      alternative_id )
            using index enable;


